import React, { useState, useEffect, useRef } from "react";
import { Stage, Layer, Image, Line, Circle, Group, Text } from "react-konva";
import { theme, Button, Space, Typography, Card, Tooltip, Tag } from "antd";
import { PlusOutlined, DeleteOutlined, SaveOutlined, UndoOutlined, DragOutlined } from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { DetectionArea } from "../../../dashboard/data/mockData";

const { useToken } = theme;

interface Props {
  imageUrl: string;
  areas: DetectionArea[];
  onSave: (updatedAreas: DetectionArea[]) => void;
}

export default function DetectionAreaEditor({ imageUrl, areas, onSave }: Props) {
  const { token } = useToken();
  const { t } = useI18n(["management"]);
  
  const [bgImage, setBgImage] = useState<HTMLImageElement | null>(null);
  const [localAreas, setLocalAreas] = useState<DetectionArea[]>(areas);
  const [selectedAreaId, setSelectedAreaId] = useState<string | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [currentPoints, setCurrentPoints] = useState<number[]>([]);
  
  const stageRef = useRef<any>(null);

  useEffect(() => {
    const img = new window.Image();
    img.src = imageUrl;
    img.onload = () => setBgImage(img);
    setLocalAreas(areas);
  }, [imageUrl, areas]);

  const handleStageClick = (e: any) => {
    if (!isDrawing) return;
    
    const stage = e.target.getStage();
    const pos = stage.getPointerPosition();
    if (!pos) return;

    setCurrentPoints(prev => [...prev, pos.x, pos.y]);
  };

  const handleFinishDrawing = () => {
    if (currentPoints.length < 6) {
      // minimum 3 points to make a polygon
      setIsDrawing(false);
      setCurrentPoints([]);
      return;
    }

    const newId = `new-${Date.now()}`;
    const newArea: DetectionArea = {
      id: newId,
      name: `${t("manager.detector_area")} ${localAreas.length + 1}`,
      points: currentPoints,
      color: "rgba(24, 144, 255, 0.3)"
    };
    setLocalAreas([...localAreas, newArea]);
    setSelectedAreaId(newId);
    setIsDrawing(false);
    setCurrentPoints([]);
  };

  const handleAddArea = () => {
    setIsDrawing(true);
    setSelectedAreaId(null);
    setCurrentPoints([]);
  };

  const handleRemoveArea = () => {
    if (!selectedAreaId) return;
    setLocalAreas(localAreas.filter(a => a.id !== selectedAreaId));
    setSelectedAreaId(null);
  };

  const handleAreaDragEnd = (areaId: string, e: any) => {
    const node = e.target;
    const dx = node.x();
    const dy = node.y();

    setLocalAreas(prev => prev.map(a => {
      if (a.id !== areaId) return a;
      const nextPoints = a.points.map((p, i) => i % 2 === 0 ? p + dx : p + dy);
      return { ...a, points: nextPoints };
    }));

    // Reset node position so points define the absolute location
    node.x(0);
    node.y(0);
  };

  const handlePointDragMove = (areaId: string, pointIndex: number, e: any) => {
    const stage = e.target.getStage();
    const pos = stage.getPointerPosition();
    if (!pos) return;

    setLocalAreas(prev => prev.map(a => {
      if (a.id !== areaId) return a;
      const nextPoints = [...a.points];
      nextPoints[pointIndex * 2] = pos.x;
      nextPoints[pointIndex * 2 + 1] = pos.y;
      return { ...a, points: nextPoints };
    }));
  };

  return (
    <Card 
      size="small" 
      title={
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <Space>
            <span>{t("manager.detector_area_editor")}</span>
            {isDrawing && (
              <Tag color="cyan" icon={<PlusOutlined />} className="blink-icon">
                {t("manager.drawing_mode")}
              </Tag>
            )}
          </Space>
          <Space>
            {isDrawing ? (
              <Button size="small" type="primary" onClick={handleFinishDrawing} disabled={currentPoints.length < 6}>
                {t("manager.finish")}
              </Button>
            ) : (
              <Button size="small" icon={<PlusOutlined />} onClick={handleAddArea}>{t("manager.add")}</Button>
            )}
            <Button size="small" danger icon={<DeleteOutlined />} onClick={handleRemoveArea} disabled={!selectedAreaId}>{t("manager.delete")}</Button>
            <Button size="small" type="primary" icon={<SaveOutlined />} onClick={() => onSave(localAreas)}>{t("manager.save")}</Button>
          </Space>
        </div>
      }
      bodyStyle={{ padding: 0, overflow: "hidden", background: "#000" }}
    >
      <div style={{ position: "relative", width: "100%", height: 500, overflow: "auto" }}>
        <Stage 
          width={800} 
          height={500} 
          ref={stageRef} 
          onClick={handleStageClick}
          onDblClick={handleFinishDrawing}
          style={{ cursor: isDrawing ? "crosshair" : "default" }}
        >
          <Layer>
            {bgImage && (
              <Image 
                image={bgImage} 
                width={800} 
                height={500} 
                opacity={0.6} 
              />
            )}
            
            {/* Render Existing Areas */}
            {localAreas.map((area) => {
              const isSelected = area.id === selectedAreaId;
              return (
                <Group key={area.id} onClick={(e) => { e.cancelBubble = true; setSelectedAreaId(area.id); }}>
                  <Line
                    points={area.points}
                    fill={isSelected ? "rgba(255, 77, 79, 0.4)" : (area.color || "rgba(24, 144, 255, 0.2)")}
                    stroke={isSelected ? token.colorError : (area.color ? "#fff" : token.colorPrimary)}
                    strokeWidth={isSelected ? 3 : 2}
                    closed
                    tension={0}
                    draggable={isSelected}
                    onDragEnd={(e) => handleAreaDragEnd(area.id, e)}
                  />
                  {isSelected && Array.from({ length: area.points.length / 2 }).map((_, idx) => (
                    <Circle
                      key={`${area.id}-p-${idx}`}
                      x={area.points[idx * 2]}
                      y={area.points[idx * 2 + 1]}
                      radius={6}
                      fill={token.colorError}
                      stroke="#fff"
                      strokeWidth={2}
                      draggable
                      onDragMove={(e) => handlePointDragMove(area.id, idx, e)}
                    />
                  ))}
                  <Text 
                    x={area.points[0]} 
                    y={area.points[1] - 20} 
                    text={area.name} 
                    fill="#fff" 
                    fontSize={12} 
                    fontStyle="bold"
                    shadowBlur={5}
                    shadowColor="#000"
                    listening={false}
                  />
                </Group>
              );
            })}

            {/* Render Current Drawing Line */}
            {isDrawing && currentPoints.length > 0 && (
              <Group>
                <Line
                  points={currentPoints}
                  stroke={token.colorInfo}
                  strokeWidth={2}
                  tension={0}
                  lineCap="round"
                  lineJoin="round"
                />
                {Array.from({ length: currentPoints.length / 2 }).map((_, idx) => (
                  <Circle
                    key={`draw-p-${idx}`}
                    x={currentPoints[idx * 2]}
                    y={currentPoints[idx * 2 + 1]}
                    radius={4}
                    fill={token.colorInfo}
                  />
                ))}
              </Group>
            )}
          </Layer>
        </Stage>

        {!selectedAreaId && !isDrawing && localAreas.length > 0 && (
          <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", pointerEvents: "none" }}>
            <Typography.Text style={{ color: "#fff", background: "rgba(0,0,0,0.5)", padding: "4px 12px", borderRadius: 4 }}>
              {t("manager.select_area_to_edit")}
            </Typography.Text>
          </div>
        )}

        {isDrawing && (
          <div style={{ position: "absolute", bottom: 16, left: 16, pointerEvents: "none" }}>
            <Typography.Text style={{ color: "#fff", background: "rgba(0,0,0,0.7)", padding: "6px 16px", borderRadius: 20, boxShadow: "0 4px 10px rgba(0,0,0,0.3)" }}>
              <DragOutlined style={{ marginRight: 8 }} />
              {t("manager.drawing_instruction")}
            </Typography.Text>
          </div>
        )}
      </div>
    </Card>
  );
}
